constraint.script:
"import com.intellij.psi.PsiClass
import com.intellij.psi.JavaPsiFacade
import com.intellij.psi.search.GlobalSearchScope

def psiClass = __context__

if (psiClass instanceof PsiClass) {
    // 1. Get the current project context
    def project = psiClass.getProject()

    // 2. Locate the target interface class using the JavaFacade
    def interfaceClass = JavaPsiFacade.getInstance(project).findClass(
            "actions.Action",
            GlobalSearchScope.allScope(project)
    )

    if (interfaceClass != null) {
        // 3. Check if your class extends or implements that target interface
        // The second parameter 'true' tells it to search recursively up the inheritance chain
        boolean implementsInterface = psiClass.isInheritor(interfaceClass, true)

        return !implementsInterface
    }
}

return true
"

"import com.intellij.psi.PsiClass

// 1. Get the actual PSI Class element from the search context
def psiClass = __context__

if (psiClass instanceof PsiClass) {
    // 2. Check if the class is missing your specific annotation
    return !psiClass.hasAnnotation("actions.CommandAction")
}

return false
"

variableDefinition.script:
"import com.intellij.psi.PsiClass

def psiClass = __context__
if (psiClass instanceof PsiClass) {
    def className = psiClass.getName()
    if (className.endsWith("Action")) {
        className = className.substring(0, className.length() - 6)
    }
    def commandName = className.replaceAll(/([a-z0-9])([A-Z])/, '$1_$2').toLowerCase()

    // Just return the raw string text without wrapping it in manual escaped quotes!
    // IntelliJ's replacement engine will treat the template's literal quotes correctly.
    return commandName
}
return "default_command"
"
